// Validate secret and load content + scene data
const data = $input.first().json;
const expectedSecret = $env.N8N_WEBHOOK_HMAC_SECRET;

if (!expectedSecret) throw new Error('N8N_WEBHOOK_HMAC_SECRET not configured');

const headers = data.headers || {};
const body    = data.body    || data || {};
const receivedSecret = headers['x-webhook-secret'] || body.secret || '';

if (receivedSecret !== expectedSecret) throw new Error('Invalid webhook secret');

const content_id = body.content_id || '';
if (!content_id) throw new Error('Missing required field: content_id');

// Load content metadata (format, brand data)
const contentResp = await $http.request({
  method: 'POST',
  url:    'http://localhost:5678/webhook/cf-read-content',
  body:   { secret: expectedSecret, action: 'read_content', content_id },
  json:   true
});
const content = contentResp.content || {};

// Load all scenes with their asset URLs and statuses
const scenesResp = await $http.request({
  method: 'POST',
  url:    'http://localhost:5678/webhook/cf-scene',
  body:   { secret: expectedSecret, action: 'list_scenes', content_id },
  json:   true
});
const scenes = scenesResp.scenes || [];

if (scenes.length === 0) throw new Error(`No scenes found for content_id: ${content_id}`);

return [{ json: { content_id, content, scenes, authenticated: true } }];

// Validate all scenes have status 'generated' and a valid asset_url
const { content_id, content, scenes } = $input.first().json;

const pendingScenes = scenes.filter(s => s.status !== 'generated' || !s.asset_url);

if (pendingScenes.length > 0) {
  // Return error — some scenes are not ready yet
  // Use respondToWebhook approach: throw to let error handler respond,
  // OR return a special marker and handle in response node.
  // We throw with a structured message to surface to the caller.
  const pendingNums = pendingScenes.map(s => s.scene_number);
  throw new Error(JSON.stringify({
    status: 'error',
    message: 'Scenes not ready',
    pending_scenes: pendingNums,
    total_scenes: scenes.length,
    ready_scenes: scenes.length - pendingScenes.length
  }));
}

return [{ json: { content_id, content, scenes } }];

// Build the ReelProps object for Remotion render
const { content_id, content, scenes } = $input.first().json;

// Map content format to Remotion composition name
const formatMap = {
  'reel-motion-text':       'ReelMotionText',
  'reel-meme-skit':         'ReelMemeSkit',
  'reel-feature-showcase':  'ReelFeatureShowcase',
  'reel-teaser':            'ReelTeaser'
};
const composition = formatMap[content.format] || 'ReelMotionText';

// Build ReelProps
const reelProps = {
  scenes: scenes.map(s => ({
    id:              `scene-${s.scene_number}`,
    type:            (s.asset_url || '').endsWith('.mp4') ? 'video' : 'image',
    src:             s.asset_url,
    durationInFrames: Math.round((s.duration || 3) * 30), // 30fps, default 3s
    text:            s.dialogue || '',
    transition:      s.transition || 'fade'
  })),
  brand: {
    name:         content.brand_name         || '',
    primaryColor: content.brand_palette?.primary || '#FF6B00',
    font:         content.brand_typography    || 'Inter'
  }
};

// Include audio if present
if (content.audio_url) {
  reelProps.audio = {
    url:    content.audio_url,
    volume: content.audio_volume || 0.8
  };
}

return [{ json: { content_id, content, composition, reelProps } }];

// Trigger Remotion render via creative-pipeline webhook
const { content_id, content, composition, reelProps } = $input.first().json;
const expectedSecret = $env.N8N_WEBHOOK_HMAC_SECRET;

let renderResult;
try {
  renderResult = await $http.request({
    method: 'POST',
    url:    'http://localhost:5678/webhook/creative-pipeline',
    body:   {
      type:        'video-composition',
      prompt:      content.title || content_id,
      model:       'remotion',
      composition: composition,
      input_props: reelProps,
      output_name: `${content_id}-rough-cut`,
      agent_id:    'content-factory'
    },
    json:    true,
    timeout: 600000
  });
} catch (err) {
  throw new Error(JSON.stringify({
    status:  'error',
    message: 'Remotion render failed',
    error:   err.message
  }));
}

if (renderResult.status !== 'ok') {
  throw new Error(JSON.stringify({
    status:  'error',
    message: 'Remotion render returned non-ok status',
    details: renderResult
  }));
}

const render_id    = renderResult.render_id   || null;
const rough_cut_url = renderResult.result_url  || null;

return [{ json: { content_id, content, composition, render_id, rough_cut_url } }];

// Store rough cut URL in NocoDB and advance pipeline step
const { content_id, content, composition, render_id, rough_cut_url } = $input.first().json;
const expectedSecret = $env.N8N_WEBHOOK_HMAC_SECRET;

try {
  await $http.request({
    method: 'POST',
    url:    'http://localhost:5678/webhook/cf-update-content',
    body:   {
      secret:       expectedSecret,
      action:       'update_content',
      content_id,
      rough_cut_url,
      current_step: 10,
      status:       'awaiting_validation'
    },
    json: true
  });
} catch (err) {
  // Log but continue — storage failure should not block Kitsu sync
  console.error(`Failed to store rough cut URL: ${err.message}`);
}

return [{ json: { content_id, content, composition, render_id, rough_cut_url } }];

// Sync Kitsu: mark step 10 (Rough Cut) as done and upload preview
const { content_id, content, composition, render_id, rough_cut_url } = $input.first().json;
const expectedSecret = $env.N8N_WEBHOOK_HMAC_SECRET;

// Update task status for step 10
try {
  await $http.request({
    method: 'POST',
    url:    'http://localhost:5678/webhook/cf-kitsu-sync',
    body:   {
      secret:     expectedSecret,
      action:     'update_task_status',
      content_id,
      step:       10,
      status:     'done'
    },
    json: true
  });
} catch (err) {
  console.error(`Kitsu task status sync failed: ${err.message}`);
}

// Upload preview if we have a render URL
if (rough_cut_url) {
  try {
    await $http.request({
      method: 'POST',
      url:    'http://localhost:5678/webhook/cf-kitsu-sync',
      body:   {
        secret:     expectedSecret,
        action:     'upload_preview',
        content_id,
        preview_url: rough_cut_url
      },
      json: true
    });
  } catch (err) {
    console.error(`Kitsu preview upload failed: ${err.message}`);
  }
}

return [{ json: { content_id, render_id, rough_cut_url, composition } }];
